// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract ClosedPresaleMint {
    enum State { CLOSED, PRESALE, PUBLIC }
    State public currentState = State.CLOSED;

    address private _owner;
    uint256 private _price;
    uint256 private _totalSupply;
    uint256 private _maxSupply;
    mapping(address => bool) private _claimedWhitelistStatus;

    event PresaleStarted();
    event PublicSaleStarted();
    event NFTMinted(address indexed buyer, uint256 indexed tokenId);
    event PublicNFTMinted(address indexed buyer, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == _owner, "Ownable: caller is not the owner");
        _;
    }

    constructor(uint256 price_, uint256 maxSupply_) {
        _owner = msg.sender;
        _price = price_;
        _maxSupply = maxSupply_;
    }

    function price() public view returns (uint256) {
        return _price;
    }

    function totalSupply() public view returns (uint256) {
        return _totalSupply;
    }

    function maxSupply() public view returns (uint256) {
        return _maxSupply;
    }

    function claimedWhitelistStatus(address account) public view returns (bool) {
        return _claimedWhitelistStatus[account];
    }

    function startPresale() public onlyOwner {
        require(currentState == State.CLOSED, "Presale cannot be started yet");
        currentState = State.PRESALE;
        emit PresaleStarted();
    }

    function startPublicSale() public onlyOwner {
        require(currentState == State.PRESALE, "Public sale cannot be started yet");
        currentState = State.PUBLIC;
        emit PublicSaleStarted();
    }

    function mintNFT() external payable {
        require(currentState == State.PRESALE, "Presale is not active");
        require(!_claimedWhitelistStatus[msg.sender], "Address already claimed");
        require(msg.value == _price, "Incorrect payment amount");
        require(_totalSupply + 1 <= _maxSupply, "Exceeds maximum supply");

        _claimedWhitelistStatus[msg.sender] = true;
        _totalSupply += 1;

        emit NFTMinted(msg.sender, _totalSupply);
    }

    function mintPublicNFT(uint256 amount) external payable {
        require(currentState == State.PUBLIC, "Public sale is not active");
        require(amount > 0, "Amount must be greater than zero");
        require(msg.value == amount * _price, "Incorrect payment amount");
        require(_totalSupply + amount <= _maxSupply, "Exceeds maximum supply");

        _totalSupply += amount;

        emit PublicNFTMinted(msg.sender, amount);
    }
}
